import React from 'react';
import './Templates.css';

const Templates: React.FC = () => {
  const templates = [
    {
      id: 'ai-cfo',
      title: 'AI CFO',
      description: 'Financial planning, budgeting, and strategic financial analysis',
      features: ['Budget Analysis', 'Financial Forecasting', 'Cost Optimization', 'ROI Tracking'],
      icon: '💰'
    },
    {
      id: 'hr',
      title: 'HR',
      description: 'Human resources management and employee lifecycle',
      features: ['Recruitment', 'Employee Onboarding', 'Performance Reviews', 'Payroll Management'],
      icon: '👥'
    },
    {
      id: 'finance',
      title: 'Finance',
      description: 'KYC, KYB, invoice processing, tax returns, and audit management',
      features: ['KYC/KYB Verification', 'Invoice Processing', 'Tax Returns', 'Audit Management'],
      icon: '📊'
    },
    {
      id: 'customer-support',
      title: 'Customer Support',
      description: '24/7 customer service and support automation',
      features: ['Live Chat', 'Ticket Management', 'FAQ Automation', 'Customer Satisfaction'],
      icon: '🎧'
    },
    {
      id: 'competitor-analysis',
      title: 'Competitor Analysis',
      description: 'Market research and competitive intelligence',
      features: ['Market Research', 'Competitor Tracking', 'Price Analysis', 'Trend Monitoring'],
      icon: '🔍'
    },
    {
      id: 'voice-calling',
      title: 'Voice Calling',
      description: 'AI-powered voice interactions and call management',
      features: ['Voice Recognition', 'Call Routing', 'Transcription', 'Sentiment Analysis'],
      icon: '📞'
    },
    {
      id: 'property-management',
      title: 'Property Management',
      description: 'Real estate and property management automation',
      features: ['Tenant Management', 'Maintenance Tracking', 'Rent Collection', 'Property Analytics'],
      icon: '🏠'
    },
    {
      id: 'motion',
      title: 'Motion',
      description: 'Just describe your requirement in prompt. Deploy in one click.',
      features: ['Prompt to Agent Creation', 'One-Click Deploy', 'Custom Workflows', 'API Integration'],
      icon: '⚡'
    }
  ];

  return (
    <div className="templates-section">
      <div className="templates-container">
        <div className="templates-header">
          <h2 className="templates-title">AI Agent Templates</h2>
          <p className="templates-subtitle">
            Choose from our pre-built templates or create your own custom AI agent
          </p>
        </div>
        
        <div className="templates-grid">
          {templates.map((template) => (
            <div key={template.id} className="template-card">
              <div className="template-card-header">
                <div className="template-icon">{template.icon}</div>
                <h3 className="template-title">{template.title}</h3>
              </div>
              
              <p className="template-description">{template.description}</p>
              
              <div className="template-features">
                {template.features.map((feature, index) => (
                  <span key={index} className="feature-tag">{feature}</span>
                ))}
              </div>
              
              <div className="template-actions">
                <button className="template-button primary">
                  Use Template
                </button>
                <button className="template-button secondary">
                  Customize
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Templates;
